// n8n Code node (JavaScript) — Run Once for All Items
// Input: items from Compression→Decompress (each with .binary fileN)
// Output: one item with { messages: [...] }

const filesByName = {};
for (const it of items) {
  if (!it.binary) continue;
  for (const key of Object.keys(it.binary)) {
    const b = it.binary[key];
    if (!b?.fileName) continue;
    filesByName[b.fileName] = {
      fileName: b.fileName,
      mimeType: b.mimeType,
      // some n8n versions expose .data, some .base64 — support both
      base64: b.base64 || b.data,
    };
  }
}

// Find the chat .txt file
const txtFileName = Object.keys(filesByName).find(n =>
  n.toLowerCase().endsWith('.txt')
);
if (!txtFileName) {
  return [{ json: { ok: false, messages: [], error: 'No .txt chat file found in the decompressed ZIP.' } }];
}

// Read chat text
const chatText = Buffer
  .from(filesByName[txtFileName].base64, 'base64')
  .toString('utf8');

// Header regex: "dd/mm/yyyy, hh:mm - Sender: Message" (supports am/pm and 24h; hyphen or en-dash)
const headerRe = /^(\d{1,2}\/\d{1,2}\/\d{4}),\s(\d{1,2}:\d{2}(?:\s?(?:am|pm))?)\s[-–]\s([^:]+?):\s(.*)$/i;

function parseToISO(dateStr, timeStr) {
  // expects dd/mm/yyyy (typical WA export outside US)
  const [day, month, year] = dateStr.split('/').map(Number);
  let h = 0, m = 0;
  if (/am|pm/i.test(timeStr)) {
    const ampm = timeStr.slice(-2).toLowerCase();
    const [hh, mm] = timeStr.replace(/am|pm/i, '').trim().split(':').map(Number);
    h = hh; m = mm;
    if (ampm === 'pm' && h < 12) h += 12;
    if (ampm === 'am' && h === 12) h = 0;
  } else {
    [h, m] = timeStr.split(':').map(Number);
  }
  return new Date(year, month - 1, day, h, m).toISOString();
}

// Try to resolve a file mention in text to a decompressed file
function mediaFromText(line) {
  if (!line) return null;
  const m = line.match(
    /([A-Za-z0-9_\-]+?\.(?:jpe?g|png|webp|gif|heic|mp4|mov|m4v|pdf|docx?|xlsx?|zip|rar|mp3|ogg))/i
  );
  if (!m) return null;
  const fname = m[1];
  const f = filesByName[fname];
  if (!f) return null;
  return { filename: f.fileName, mimeType: f.mimeType, base64: f.base64 };
}

const lines = chatText.replace(/\uFEFF/g, '').split(/\r?\n/);
const messages = [];
let last = null;

for (const raw of lines) {
  if (!raw) continue;

  const m = raw.match(headerRe);
  if (m) {
    const [, date, time, sender, messageRaw0] = m;
    let messageRaw = messageRaw0 || '';

    // Skip system banner
    if (/^Messages and calls are end-to-end encrypted/i.test(messageRaw)) continue;

    // Is this a media announcement line?
    let media = mediaFromText(messageRaw);
    const saysFileAttached = /\(file attached\)\s*$/i.test(messageRaw);
    const saysMediaOmitted = /<Media omitted>/.test(messageRaw);

    const msg = {
      timestamp: parseToISO(date, time),
      sender: sender.trim(),
      message: messageRaw,
      media: media || null,
    };

    // If it's a media line (explicit file or "(file attached)"):
    // - drop the label from bubble
    // - expect the next continuation line(s) to be the caption
    if (media || saysFileAttached || saysMediaOmitted) {
      msg.message = '';            // don't show "IMG-... (file attached)"
      msg._expectCaption = true;   // next non-header lines become caption
    }

    last = msg;
    messages.push(msg);

  } else if (last) {
    // Continuation line (no sender/timestamp)
    const cont = raw.trim();
    if (!cont) continue;

    // If we just had a media message (or are still expecting), treat as caption
    if (last._expectCaption || last.media) {
      last.caption = (last.caption ? last.caption + '\n' : '') + cont;
      last._expectCaption = false;
    } else {
      // Multiline text message continuation
      last.message = (last.message ? last.message + '\n' : '') + cont;
    }
  }
}

// Cleanup helper flags
for (const m of messages) delete m._expectCaption;

return [{ json: { messages } }];
